// src/pages/Home.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { foodsAPI } from '../services/api';
import FoodCard from '../components/FoodCard';
import { useAuth } from '../context/AuthContext';

const CATEGORIES = [
  { name: 'All', icon: '🍽️', value: null },
  { name: 'Pizza', icon: '🍕', value: 'pizza' },
  { name: 'Burger', icon: '🍔', value: 'burger' },
  { name: 'Cake', icon: '🎂', value: 'cake' },
  { name: 'Salad', icon: '🥗', value: 'salad' },
  { name: 'Sandwich', icon: '🥪', value: 'sandwich' },
  { name: 'Drink', icon: '🥤', value: 'drink' },
  { name: 'Sushi', icon: '🍱', value: 'sushi' },
  { name: 'Pasta', icon: '🍝', value: 'pasta' }
];

const Home = () => {
  const [foods, setFoods] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [searchInput, setSearchInput] = useState('');
  const [pagination, setPagination] = useState({ total: 0, pages: 1, page: 1 });
  const { user } = useAuth();
  const navigate = useNavigate();

  // ================= FETCH FOODS =================
  const fetchFoods = async (category = null, search = '') => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      
      if (category) params.append('category', category);
      if (search) params.append('search', search);
      params.append('page', 1);
      params.append('limit', 20);

      const response = await foodsAPI.getAll();
      
      // 🔥 Si le backend n'a pas les params intégrés, filtrer au frontend
      let filteredFoods = response.data.foods || [];

      if (category) {
        filteredFoods = filteredFoods.filter(
          food => food.category?.toLowerCase() === category.toLowerCase()
        );
      }

      if (search) {
        filteredFoods = filteredFoods.filter(
          food => food.name.toLowerCase().includes(search.toLowerCase())
        );
      }

      setFoods(filteredFoods);
      setPagination({
        total: filteredFoods.length,
        pages: Math.ceil(filteredFoods.length / 20),
        page: 1
      });

    } catch (error) {
      console.error('Error fetching foods:', error);
    } finally {
      setLoading(false);
    }
  };

  // ================= INITIAL LOAD =================
  useEffect(() => {
    fetchFoods(selectedCategory, searchInput);
  }, []);

  // ================= SEARCH HANDLER =================
  const handleSearch = (e) => {
    e.preventDefault();
    setSelectedCategory(null); // Reset category when searching
    fetchFoods(null, searchInput);
  };

  // ================= CATEGORY FILTER HANDLER =================
  const handleCategoryClick = (categoryValue) => {
    setSelectedCategory(categoryValue);
    setSearchInput(''); // Reset search when filtering by category
    fetchFoods(categoryValue, '');
  };

  return (
    <div style={styles.page}>
      {/* ================= NAVBAR ================= */}
      <div style={styles.navbar}>
        <div style={styles.navContent}>
          <div style={styles.logo}>Foody<span style={styles.dot}>.</span></div>
          <div style={styles.navLinks}>
            <button style={styles.navLink}>Home</button>
            <button style={styles.navLink}>My Orders</button>
          </div>
          <div style={styles.navRight}>
            <span style={styles.userName}>{user?.fullName || 'Guest'}</span>
            <button style={styles.cartBtn}>🛒 Cart</button>
            <button style={styles.logoutBtn}>Logout</button>
          </div>
        </div>
      </div>

      {/* ================= HERO BANNER ================= */}
      <div style={styles.hero}>
        <div style={styles.heroContent}>
          <h1 style={styles.heroTitle}>Order your<br />favourite food 🔊</h1>
          <p style={styles.heroSubtitle}>Fast delivery, fresh meals — right to your door</p>
        </div>
        <div style={styles.heroEmoji}>🍔</div>
      </div>

      {/* ================= SEARCH BAR ================= */}
      <div style={styles.searchSection}>
        <form onSubmit={handleSearch} style={styles.searchForm}>
          <input
            type="text"
            placeholder="Search pizza, burger..."
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            style={styles.searchInput}
          />
          <button type="submit" style={styles.searchBtn}>Search</button>
        </form>
      </div>

      {/* ================= CATEGORY FILTERS ================= */}
      <div style={styles.categoriesSection}>
        <div style={styles.categoriesScroll}>
          {CATEGORIES.map((cat) => (
            <button
              key={cat.value || 'all'}
              onClick={() => handleCategoryClick(cat.value)}
              style={{
                ...styles.categoryBtn,
                ...(selectedCategory === cat.value ? styles.categoryBtnActive : {})
              }}
            >
              <span style={styles.categoryIcon}>{cat.icon}</span>
              {cat.name}
            </button>
          ))}
        </div>
      </div>

      {/* ================= FOODS GRID ================= */}
      <div style={styles.container}>
        <h2 style={styles.title}>
          {selectedCategory ? `${selectedCategory.toUpperCase()}` : 'All Items'}
          <span style={styles.count}>({foods.length} items)</span>
        </h2>

        {loading ? (
          <div style={styles.loading}>Loading foods...</div>
        ) : foods.length === 0 ? (
          <div style={styles.empty}>
            <p style={styles.emptyText}>No foods found 😢</p>
          </div>
        ) : (
          <div style={styles.grid}>
            {foods.map((food) => (
              <FoodCard key={food._id} food={food} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  page: {
    minHeight: '100vh',
    background: '#F8F6F2',
  },
  navbar: {
    background: '#fff',
    borderBottom: '1px solid #EBEBEB',
    padding: '0 2rem',
    position: 'sticky',
    top: 0,
    zIndex: 100,
  },
  navContent: {
    maxWidth: '1200px',
    margin: '0 auto',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '0.75rem 0',
  },
  logo: {
    fontSize: '20px',
    fontWeight: '600',
    color: '#E8621A',
  },
  dot: {
    color: '#1A1A1A',
  },
  navLinks: {
    display: 'flex',
    gap: '2rem',
  },
  navLink: {
    background: 'none',
    border: 'none',
    fontSize: '14px',
    color: '#1A1A1A',
    cursor: 'pointer',
  },
  navRight: {
    display: 'flex',
    gap: '1rem',
    alignItems: 'center',
  },
  userName: {
    fontSize: '13px',
    color: '#888780',
  },
  cartBtn: {
    background: '#E8621A',
    color: '#fff',
    border: 'none',
    borderRadius: '8px',
    padding: '8px 14px',
    fontSize: '13px',
    fontWeight: '500',
    cursor: 'pointer',
  },
  logoutBtn: {
    background: 'none',
    border: '1px solid #EBEBEB',
    borderRadius: '8px',
    padding: '8px 14px',
    fontSize: '13px',
    cursor: 'pointer',
  },
  hero: {
    background: 'linear-gradient(135deg, #E8621A 0%, #D84315 100%)',
    color: '#fff',
    padding: '3rem 2rem',
    borderRadius: '0 0 20px 20px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  heroContent: {
    flex: 1,
  },
  heroTitle: {
    fontSize: '32px',
    fontWeight: '700',
